class Solution:
    def beautifulNumbers(self, l, r):
        count = 0
        for x in range(l, r + 1):
            s = 0
            p = 1
            for ch in str(x):
                d = int(ch)
                s += d
                p *= d
            if s > 0 and p % s == 0:
                count += 1
        return count

