class Solution:
    def beautifulNumbers(self, l, r):
        def count_upto(N):
            if N <= 0:
                return 0
            digits = list(map(int, str(N)))
            L = len(digits)
            from functools import lru_cache
            @lru_cache(maxsize=None)
            def dp(pos, tight, started, s, p):
                if pos == L:
                    return 1 if (started and s > 0 and p % s == 0) else 0
                limit = digits[pos] if tight else 9
                total = 0
                for d in range(0, limit + 1):
                    nt = tight and d == limit
                    if not started and d == 0:
                        total += dp(pos + 1, nt, False, s, p)
                    else:
                        total += dp(pos + 1, nt, True, s + d, p * d)
                return total
            return dp(0, True, False, 0, 1)
        return count_upto(r) - count_upto(l - 1)

