var beautifulNumbers = function(l, r) {
    function countUpto(N) {
        if (N <= 0) return 0;
        const digits = String(N).split('').map(Number);
        const L = digits.length;
        const memo = new Map();
        function dp(pos, tight, started, s, p) {
            if (pos === L) {
                return (started && s > 0 && p % s === 0) ? 1 : 0;
            }
            const key = pos + ',' + (tight ? 1 : 0) + ',' + (started ? 1 : 0) + ',' + s + ',' + p;
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? digits[pos] : 9;
            let total = 0;
            for (let d = 0; d <= limit; d++) {
                const nt = tight && d === limit;
                if (!started && d === 0) {
                    total += dp(pos + 1, nt, false, s, p);
                } else {
                    total += dp(pos + 1, nt, true, s + d, p * d);
                }
            }
            memo.set(key, total);
            return total;
        }
        return dp(0, true, false, 0, 1);
    }
    return countUpto(r) - countUpto(l - 1);
};
